mapper.select:
SELECT 
FROM ai_capability_flow_action_log
WHERE tenant_id = #{tenantId}
  AND client_id = #{clientId}
  AND capability_id = #{capabilityId}
  AND operation = #{operation}
  AND idempotency_key = #{idempotencyKey}
  AND del_flag = 0
LIMIT 1

mapper.update:
UPDATE ai_capability_flow_action_log
SET execute_status = #{log.executeStatus},
    result_code = #{log.resultCode},
    result_snapshot = #{log.resultSnapshot},
    error_code = #{log.errorCode},
    duration_ms = #{log.durationMs},
    update_by = COALESCE(#{log.updateBy}, update_by),
    update_time = NOW()
WHERE id = #{log.id}
  AND tenant_id = #{log.tenantId}
  AND request_id = #{log.requestId}
  AND client_id = #{log.clientId}
  AND capability_id = #{log.capabilityId}
  AND operation = #{log.operation}
  AND actor_type = #{log.actorType}
  AND actor_user_id = #{log.actorUserId}
  AND service_user_id = #{log.serviceUserId}
  AND active_org_id = #{log.activeOrgId}
  AND request_digest = #{log.requestDigest}
  AND del_flag = 0
